Unfortunately, developing a complete chess game requires significant coding effort and cannot be achieved with just a few lines of code. However, if you are looking for a simple logic for a particular aspect of the game, such as moving a chess piece, here is an example of code in JavaScript:

```
// move a piece from (x1, y1) to (x2, y2)
function movePiece(x1, y1, x2, y2) {
  // check if the move is valid
  if (isValidMove(x1, y1, x2, y2)) {
    // move the piece
    chessboard[x2][y2] = chessboard[x1][y1];
    chessboard[x1][y1] = null;
  } else {
    console.log("Invalid move!");
  }
}

// check if the move is valid
function isValidMove(x1, y1, x2, y2) {
  // check if the source and destination coordinates are within the board
  if (x1 < 0 || x1 > 7 || y1 < 0 || y1 > 7 || x2 < 0 || x2 > 7 || y2 < 0 || y2 > 7) {
    return false;
  }

  // check if there is a piece at the source coordinate
  if (chessboard[x1][y1] === null) {
    return false;
  }

  // check if the piece can move to the destination coordinate
  // (this logic will vary depending on the type of piece)
  // for example, here is the logic for a pawn
  if (chessboard[x1][y1].type === "pawn") {
    // check if the pawn is moving forward
    if (x1 === x2) {
      // check if the pawn is moving one or two squares
      var dy = y2 - y1;
      if (dy === 1 && chessboard[x2][y2] === null) {
        return true;
      } else if (dy === 2 && chessboard[x1][y1+1] === null && chessboard[x2][y2] === null) {
        return true;
      }
    }
    return false;
  }

  // if none of the above conditions were met, the move is invalid
  return false;
}

// example usage: move the white pawn at (1,2) to (3,2)
movePiece(1, 2, 3, 2);
```

This code checks if a move is valid based on the current state of the chessboard, and then updates the state if the move is valid. Of course, this is just a starting point and more code would be needed to implement additional features and game logic.
